    public InstanceOf(Class<?> clazz) {
        this.clazz = clazz;
    }

    public boolean matches(Object actual) {
        if (actual == null) {
            // If actual is null, it can't match a non-primitive class
            // Only matches if clazz is also null (though that shouldn't happen in normal usage)
            return false;
        }

        Class<?> actualClass = actual.getClass();

        // Check standard assignability first
        if (clazz.isAssignableFrom(actualClass)) {
            return true;
