        if (Primitives.isPrimitiveWrapper(clazz)) {
            // We're looking for a wrapper type like Integer.class
            // Get the corresponding primitive (e.g., int.class)
            Class<?> correspondingPrimitive = Primitives.primitiveTypeOf(clazz);
            if (correspondingPrimitive != null && correspondingPrimitive.equals(actualClass)) {
                return true;
            }
        } else if (Primitives.isPrimitiveWrapper(actualClass)) {
            // We have a wrapper type as actual (like Integer), checking against primitive (like int)
            Class<?> correspondingPrimitive = Primitives.primitiveTypeOf(actualClass);
            if (correspondingPrimitive != null && correspondingPrimitive.equals(clazz)) {
                return true;
            }
        }

        return false;
    }

    public void describeTo(Description description) {
        description.appendText("isA(" + clazz.getName() + ")");
    }
